void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz-GetBlur1(vUv);
ret += (texture(sampler_rand00,vUv)-texture(sampler_rand01,vUv))*0.75;

